1	import { defineStore } from 'pinia'
2	import { ref } from 'vue'
3	import type { ReceivingReceipt, PutawayTask, ReceiptType, ReceiptStatus, Discrepancy } from '@/services/adapters/api-adapter.interface'
4	import type { PaginatedResponse } from '@/types/api'
5	import { operationsApi } from './api'
6	import { normalizeError } from '@/utils/error-normalizer'
7	import type { ApiError } from '@/types/api'
8	
9	export const useOperationsStore = defineStore('operations', () => {
10	  const receipts = ref<ReceivingReceipt[]>([])
11	  const currentReceipt = ref<ReceivingReceipt | null>(null)
12	  const putawayTasks = ref<PutawayTask[]>([])
13	  const discrepancies = ref<Discrepancy[]>([])
14	  const loading = ref(false)
15	  const error = ref<ApiError | null>(null)
16	  const totalReceipts = ref(0)
17	
18	  const api = operationsApi()
19	
20	  async function fetchReceipts(page = 0, size = 25) {
21	    loading.value = true
22	    error.value = null
23	    try {
24	      const res = await api.getReceipts({ page, size })
25	      const payload = res.data as ReceivingReceipt[] | PaginatedResponse<ReceivingReceipt>
26	      if (Array.isArray(payload)) {
27	        receipts.value = payload
28	        totalReceipts.value = payload.length
29	      } else if (payload && Array.isArray(payload.content)) {
30	        receipts.value = payload.content
31	        totalReceipts.value = payload.totalElements ?? payload.content.length
32	      } else {
33	        receipts.value = []
34	        totalReceipts.value = 0
35	      }
36	    } catch (e) {
37	      error.value = normalizeError(e)
38	    } finally {
39	      loading.value = false
40	    }
41	  }
42	
43	  async function fetchReceipt(id: number) {
44	    loading.value = true
45	    error.value = null
46	    try {
47	      const res = await api.getReceipt(id)
48	      currentReceipt.value = res.data
49	    } catch (e) {
50	      error.value = normalizeError(e)
51	    } finally {
52	      loading.value = false
53	    }
54	  }
55	
56	  async function fetchDiscrepancies(receiptId: number) {
57	    try {
58	      const res = await api.getDiscrepancies(receiptId)
59	      const payload = res.data
60	      if (Array.isArray(payload)) {
61	        discrepancies.value = payload
62	      } else {
63	        discrepancies.value = []
64	      }
65	    } catch (e) {
66	      discrepancies.value = []
67	    }
68	  }
69	
70	  async function fetchAllDiscrepancies() {
71	    loading.value = true
72	    try {
73	      if (receipts.value.length === 0) {
74	        await fetchReceipts(0, 100)
75	      }
76	      const allDisc: Discrepancy[] = []
77	      for (const r of receipts.value) {
78	        try {
79	          const res = await api.getDiscrepancies(r.id)
80	          if (Array.isArray(res.data)) {
81	            allDisc.push(...res.data)
82	          }
83	        } catch { /* skip receipt if discrepancies fail */ }
84	      }
85	      discrepancies.value = allDisc
86	    } catch {
87	      discrepancies.value = []
88	    } finally {
89	      loading.value = false
90	    }
91	  }
92	
93	  async function fetchPutawayTasks() {
94	    loading.value = true
95	    try {
96	      if (receipts.value.length === 0) {
97	        await fetchReceipts(0, 100)
98	      }
99	      const allTasks: PutawayTask[] = []
100	      const putawayReceipts = receipts.value.filter(r => r.status === 'PUTAWAY')
101	      for (const r of putawayReceipts) {
102	        try {
103	          const res = await api.getPutawayTasks(r.id)
104	          if (Array.isArray(res.data)) {
105	            allTasks.push(...res.data)
106	          }
107	        } catch { /* skip receipt */ }
108	      }
109	      putawayTasks.value = allTasks
110	    } catch {
111	      putawayTasks.value = []
112	    } finally {
113	      loading.value = false
114	    }
115	  }
116	
117	  async function fetchPutawayTasksForReceipt(receiptId: number) {
118	    try {
119	      const res = await api.getPutawayTasks(receiptId)
120	      if (Array.isArray(res.data)) {
121	        putawayTasks.value = res.data
122	      }
123	    } catch {
124	      putawayTasks.value = []
125	    }
126	  }
127	
128	  async function createReceipt(data: { receiptType: ReceiptType; referenceNumber?: string; supplierName?: string; expectedDate?: string }) {
129	    loading.value = true
130	    error.value = null
131	    try {
132	      const res = await api.createReceipt(data)
133	      return res.data
134	    } catch (e) {
135	      error.value = normalizeError(e)
136	      throw e
137	    } finally {
138	      loading.value = false
139	    }
140	  }
141	
142	  async function transitionReceipt(id: number, targetState: ReceiptStatus, reason?: string) {
143	    loading.value = true
144	    error.value = null
145	    try {
146	      await api.transitionReceipt(id, { targetState, reason })
147	      await fetchReceipt(id)
148	    } catch (e) {
149	      error.value = normalizeError(e)
150	      throw e
151	    } finally {
152	      loading.value = false
153	    }
154	  }
155	
156	  async function createInspection(receiptId: number, lineId: number, inspectedQty: number, result: 'PASS' | 'FAIL', notes?: string) {
157	    loading.value = true
158	    error.value = null
159	    try {
160	      await api.createInspection({ receiptId, lineId, inspectedQty, result, notes })
161	      await fetchReceipt(receiptId)
162	    } catch (e) {
163	      error.value = normalizeError(e)
164	      throw e
165	    } finally {
166	      loading.value = false
167	    }
168	  }
169	
170	  async function createPutaway(receiptId: number, taskId: number, actualLocation?: string) {
171	    loading.value = true
172	    error.value = null
173	    try {
174	      const res = await api.createPutaway({ receiptId, taskId, actualLocation })
175	      putawayTasks.value = res.data
176	    } catch (e) {
177	      error.value = normalizeError(e)
178	      throw e
179	    } finally {
180	      loading.value = false
181	    }
182	  }
183	
184	  return {
185	    receipts,
186	    currentReceipt,
187	    putawayTasks,
188	    discrepancies,
189	    loading,
190	    error,
191	    totalReceipts,
192	    fetchReceipts,
193	    fetchReceipt,
194	    fetchDiscrepancies,
195	    fetchAllDiscrepancies,
196	    fetchPutawayTasks,
197	    fetchPutawayTasksForReceipt,
198	    createReceipt,
199	    transitionReceipt,
200	    createInspection,
201	    createPutaway,
202	  }
203	})
204	
