1	import { onMounted } from 'vue'
2	import { storeToRefs } from 'pinia'
3	import { useOperationsStore } from '../store'
4	import type { ReceiptStatus } from '@/services/adapters/api-adapter.interface'
5	
6	export function useReceiptDetail(receiptId: number) {
7	  const store = useOperationsStore()
8	  const { currentReceipt, discrepancies, putawayTasks, loading, error } = storeToRefs(store)
9	
10	  onMounted(async () => {
11	    await store.fetchReceipt(receiptId)
12	    store.fetchDiscrepancies(receiptId)
13	    if (store.currentReceipt?.status === 'PUTAWAY') {
14	      store.fetchPutawayTasksForReceipt(receiptId)
15	    }
16	  })
17	
18	  async function transition(status: ReceiptStatus, notes?: string) {
19	    await store.transitionReceipt(receiptId, status, notes)
20	    store.fetchDiscrepancies(receiptId)
21	  }
22	
23	  async function inspect(lineId: number, inspectedQty: number, result: 'PASS' | 'FAIL', notes?: string) {
24	    await store.createInspection(receiptId, lineId, inspectedQty, result, notes)
25	    store.fetchDiscrepancies(receiptId)
26	  }
27	
28	  async function putaway(taskId: number, actualLocation?: string) {
29	    await store.createPutaway(receiptId, taskId, actualLocation)
30	  }
31	
32	  function refresh() {
33	    store.fetchReceipt(receiptId)
34	    store.fetchDiscrepancies(receiptId)
35	  }
36	
37	  return {
38	    receipt: currentReceipt,
39	    discrepancies,
40	    putawayTasks,
41	    loading,
42	    error,
43	    transition,
44	    inspect,
45	    putaway,
46	    refresh,
47	  }
48	}
