28	    @Transactional
29	    public List<PutawayTask> generateTasks(Long receiptId) {
30	        // Idempotent: return existing tasks if already generated
31	        List<PutawayTask> existing = putawayTaskRepository.findByReceiptId(receiptId);
32	        if (!existing.isEmpty()) {
33	            return existing;
34	        }
35	
36	        List<InboundLine> lines = lineRepository.findByReceiptId(receiptId);
37	        List<PutawayTask> tasks = new ArrayList<>();
38	
39	        for (InboundLine line : lines) {
40	            if (line.getInspectionResult() == InboundLine.InspectionResult.PASS) {
41	                PutawayTask task = PutawayTask.builder()
42	                        .receiptId(receiptId)
43	                        .lineId(line.getId())
44	                        .suggestedLocation("ZONE-A-" + line.getItemCode())
45	                        .status(PutawayTask.TaskStatus.PENDING)
46	                        .build();
47	                tasks.add(task);
48	            }
49	        }
50	
51	        return putawayTaskRepository.saveAll(tasks);
52	    }
53	
54	    @Transactional
55	    public PutawayTask completeTask(Long receiptId, Long taskId, Long userId, String actualLocation) {
56	        PutawayTask task = putawayTaskRepository.findById(taskId)
57	                .orElseThrow(() -> new ResourceNotFoundException("PutawayTask", taskId));
58	
59	        if (!task.getReceiptId().equals(receiptId)) {
60	            throw new BusinessException("Task does not belong to the specified receipt");
61	        }
62	
63	        if (task.getStatus() != PutawayTask.TaskStatus.PENDING) {
64	            throw new BusinessException("Task is not in PENDING status");
65	        }
66	
67	        task.setStatus(PutawayTask.TaskStatus.COMPLETED);
68	        task.setCompletedBy(userId);
69	        task.setCompletedAt(LocalDateTime.now());
70	        task.setActualLocation(actualLocation != null ? actualLocation : task.getSuggestedLocation());
71	
72	        return putawayTaskRepository.save(task);
73	    }
74	
75	    @Transactional(readOnly = true)
76	    public List<PutawayTask> getByReceiptId(Long receiptId) {
77	        return putawayTaskRepository.findByReceiptId(receiptId);
78	    }
79	}
