49	    @Transactional
50	    public DeletionRequest requestDeletion(Long userId) {
51	        DeletionRequest request = DeletionRequest.builder()
52	                .userId(userId)
53	                .status(DeletionRequest.DeletionStatus.PENDING)
54	                .build();
55	
56	        request = deletionRequestRepository.save(request);
57	
58	        // Process immediately
59	        processDeletion(request);
60	
61	        return request;
62	    }
63	
64	    @Transactional
65	    public void processDeletion(DeletionRequest request) {
66	        request.setStatus(DeletionRequest.DeletionStatus.PROCESSING);
67	        deletionRequestRepository.save(request);
68	
69	        Long userId = request.getUserId();
70	
71	        User user = userRepository.findById(userId)
72	                .orElseThrow(() -> new ResourceNotFoundException("User", userId));
73	
74	        // Hard-delete all personal data records
75	        checkInRepository.deleteByUserId(userId);
76	        goalRepository.deleteByUserId(userId);
77	        assessmentRepository.deleteByUserId(userId);
78	        studyPlanRepository.deleteByUserId(userId);
79	
80	        // Hard-delete PII: replace identifiers with non-reversible placeholders
81	        String anonymizedId = "anon_" + java.util.UUID.randomUUID().toString().substring(0, 8);
82	        user.setUsername(anonymizedId);
83	        user.setEmail(null);
84	        user.setPhone(null);
85	        user.setPasswordHash("ACCOUNT_DELETED");
86	        user.setStatus(User.UserStatus.DELETED);
87	        userRepository.save(user);
88	
89	        // Delete all sessions for this user
90	        sessionRepository.deleteByUserId(userId);
91	
92	        // Mark deletion complete
93	        request.setStatus(DeletionRequest.DeletionStatus.COMPLETED);
94	        request.setProcessedAt(LocalDateTime.now());
95	        deletionRequestRepository.save(request);
96	
97	        log.info("Account deletion completed for user={}", "***" + (userId % 1000));
98	    }
