51	    @Transactional
52	    @SuppressWarnings("unchecked")
53	    public String importAccountData(Long userId, Map<String, Object> data) {
54	        int studyCount = 0;
55	        int fitnessCount = 0;
56	        int goalCount = 0;
57	        int checkInCount = 0;
58	
59	        // Restore profile metadata if present
60	        if (data.containsKey("profileData")) {
61	            try {
62	                Map<String, Object> profile = (Map<String, Object>) data.get("profileData");
63	                restoreProfile(userId, profile);
64	            } catch (Exception e) {
65	                log.warn("Failed to restore profile metadata: {}", e.getMessage());
66	            }
67	        }
68	
69	        // Import study data if present
70	        if (data.containsKey("studyData")) {
71	            try {
72	                StudyExportData studyData = objectMapper.convertValue(data.get("studyData"), StudyExportData.class);
73	                studyExportImportService.importData(userId, studyData);
74	                studyCount++;
75	            } catch (Exception e) {
76	                log.warn("Failed to import study data: {}", e.getMessage());
77	            }
78	        }
79	
80	        // Import fitness assessments if present
81	        if (data.containsKey("fitnessData")) {
82	            try {
83	                List<Map<String, Object>> fitnessDataList = (List<Map<String, Object>>) data.get("fitnessData");
84	                for (Map<String, Object> assessmentData : fitnessDataList) {
85	                    AssessmentRequest request = objectMapper.convertValue(assessmentData, AssessmentRequest.class);
86	                    assessmentService.createOrUpdate(userId, request);
87	                    fitnessCount++;
88	                }
89	            } catch (Exception e) {
90	                log.warn("Failed to import fitness data: {}", e.getMessage());
91	            }
92	        }
93	
94	        // Import goals if present — build old→new ID map for check-in remapping
95	        Map<Long, Long> goalIdRemap = new HashMap<>();
96	        if (data.containsKey("goalsData")) {
97	            try {
98	                List<Map<String, Object>> goalsDataList = (List<Map<String, Object>>) data.get("goalsData");
99	                for (Map<String, Object> goalData : goalsDataList) {
100	                    Long oldGoalId = goalData.get("id") != null
101	                            ? ((Number) goalData.get("id")).longValue() : null;
102	
103	                    GoalRequest request = objectMapper.convertValue(goalData, GoalRequest.class);
104	                    GoalResponse created = goalService.create(userId, request);
105	
106	                    if (oldGoalId != null) {
107	                        goalIdRemap.put(oldGoalId, created.getId());
108	                    }
109	                    goalCount++;
110	                }
111	            } catch (Exception e) {
112	                log.warn("Failed to import goals data: {}", e.getMessage());
113	            }
114	        }
115	
116	        // Import check-ins if present — remap goalId from old to new
117	        if (data.containsKey("checkInsData")) {
118	            try {
119	                List<Map<String, Object>> checkInsDataList = (List<Map<String, Object>>) data.get("checkInsData");
120	                for (Map<String, Object> checkInData : checkInsDataList) {
121	                    Long oldGoalId = checkInData.get("goalId") != null
122	                            ? ((Number) checkInData.get("goalId")).longValue() : null;
123	                    if (oldGoalId == null) continue;
124	
125	                    Long newGoalId = goalIdRemap.getOrDefault(oldGoalId, oldGoalId);
126	                    CheckInRequest request = objectMapper.convertValue(checkInData, CheckInRequest.class);
127	                    checkInService.create(newGoalId, userId, request);
128	                    checkInCount++;
129	                }
130	            } catch (Exception e) {
131	                log.warn("Failed to import check-ins data: {}", e.getMessage());
132	            }
133	        }
134	
135	        return String.format("Import completed. Study: %d, Assessments: %d, Goals: %d, Check-ins: %d",
136	                studyCount, fitnessCount, goalCount, checkInCount);
137	    }
