68	        // Study plan stats
69	        int planCount = studyPlanRepository.findByUserId(userId).size();
70	        summary.put("activePlans", planCount);
71	
72	        // Streaks
73	        List<Streak> streaks = streakRepository.findByUserId(userId);
74	        int maxStreak = streaks.stream().mapToInt(Streak::getLongestStreak).max().orElse(0);
75	        summary.put("studyStreak", maxStreak);
76	        summary.put("longestStreak", maxStreak);
77	        summary.put("recentCheckIns", 0);
78	        summary.put("pendingNotifications", 0);
79	
80	        // Recent activity
81	        List<DashboardResponse.ActivityEntry> recentActivity = new ArrayList<>();
82	        if (achievedCount > 0) {
