80	            throw new BusinessException("Export password is required. All exports must be password-protected.");
81	        }
82	
83	        ExportJob job = ExportJob.builder()
84	                .userId(userId)
85	                .exportType(request.getExportType())
86	                .status(ExportJob.JobStatus.PENDING)
87	                .passwordProtected(true)
88	                .expiresAt(LocalDateTime.now().plusDays(retentionDays))
89	                .build();
90	
91	        job = exportJobRepository.save(job);
92	
93	        try {
94	            job.setStatus(ExportJob.JobStatus.PROCESSING);
95	            exportJobRepository.save(job);
96	
97	            String exportData = generateExportData(userId, request.getExportType());
98	
99	            log.info("Generating export type={} for user={}, passwordProtected={}",
100	                    request.getExportType(), fieldMasker.mask(String.valueOf(userId)), true);
101	
102	            String filePath = writeExportFile(userId, job.getId(), exportData,
103	                    request.isPasswordProtected(), request.getExportPassword());
