105	            job.setFilePath(filePath);
106	            job.setStatus(ExportJob.JobStatus.COMPLETED);
107	            job.setCompletedAt(LocalDateTime.now());
108	            job = exportJobRepository.save(job);
109	
110	            log.info("Export job {} completed for user={}", job.getId(), fieldMasker.mask(String.valueOf(userId)));
111	        } catch (Exception e) {
