153	    private String generateExportData(Long userId, ExportJob.ExportType exportType) {
154	        try {
155	            java.util.Map<String, Object> exportBundle = new java.util.LinkedHashMap<>();
156	            exportBundle.put("exportedAt", LocalDateTime.now().toString());
157	            exportBundle.put("userId", fieldMasker.mask(String.valueOf(userId)));
158	            exportBundle.put("exportType", exportType.name());
159	            exportBundle.put("version", "2.0");
160	
161	            switch (exportType) {
162	                case STUDY_DATA:
163	                    exportBundle.put("studyData", studyExportImportService.exportData(userId));
164	                    break;
165	                case FITNESS_DATA:
166	                    exportBundle.put("fitnessData", assessmentService.getAllForUser(userId));
167	                    exportBundle.put("goalsData", goalService.getAllForUser(userId));
168	                    addCheckInsForGoals(exportBundle, goalService.getAllForUser(userId), userId);
169	                    break;
170	                case ACCOUNT_DATA:
171	                default:
172	                    addProfileMetadata(exportBundle, userId);
173	                    exportBundle.put("studyData", studyExportImportService.exportData(userId));
174	                    exportBundle.put("fitnessData", assessmentService.getAllForUser(userId));
175	                    exportBundle.put("goalsData", goalService.getAllForUser(userId));
176	                    addCheckInsForGoals(exportBundle, goalService.getAllForUser(userId), userId);
177	                    break;
