62	    @Transactional
63	    public ImportJobResponse processImport(MultipartFile file, String entityType, Long userId) {
64	        ImportJob job = ImportJob.builder()
65	                .fileName(file.getOriginalFilename())
66	                .entityType(entityType)
67	                .status(ImportJob.JobStatus.PROCESSING)
68	                .uploadedBy(userId)
69	                .build();
70	        job = importJobRepository.save(job);
71	
72	        List<ImportError> errors = new ArrayList<>();
73	        int totalRows = 0;
74	        int successCount = 0;
75	
76	        String fileName = file.getOriginalFilename() != null ? file.getOriginalFilename() : "";
77	        boolean isExcel = fileName.endsWith(".xlsx") || fileName.endsWith(".xls");
78	
79	        try {
80	            List<String[]> rows;
81	            if (isExcel) {
82	                rows = parseExcel(file.getInputStream());
83	            } else {
84	                rows = parseCsv(file.getInputStream());
85	            }
86	
87	            for (int i = 0; i < rows.size(); i++) {
88	                int rowNum = i + 2; // 1-based, skip header
89	                totalRows++;
90	                String[] fields = rows.get(i);
91	                try {
92	                    if (fields.length < 2) {
93	                        errors.add(buildError(job.getId(), rowNum, "line",
94	                                "Insufficient fields - expected at least code,name", String.join(",", fields)));
95	                        continue;
96	                    }
97	
98	                    String code = fields[0].trim();
99	                    String name = fields[1].trim();
100	
101	                    if (code.isEmpty()) {
102	                        errors.add(buildError(job.getId(), rowNum, "code", "Code is required", code));
103	                        continue;
104	                    }
105	
106	                    if (name.isEmpty()) {
107	                        errors.add(buildError(job.getId(), rowNum, "name", "Name is required", name));
108	                        continue;
109	                    }
110	
111	                    persistEntity(entityType, code, name, fields, userId);
112	                    successCount++;
113	
114	                } catch (Exception e) {
115	                    errors.add(buildError(job.getId(), rowNum, "line",
116	                            "Error: " + e.getMessage(), String.join(",", fields)));
117	                }
118	            }
119	        } catch (Exception e) {
120	            log.error("Import failed for job {}: {}", job.getId(), e.getMessage());
121	            job.setStatus(ImportJob.JobStatus.FAILED);
122	            job.setCompletedAt(LocalDateTime.now());
123	            importJobRepository.save(job);
124	            return toResponse(job, errors);
125	        }
126	
127	        if (!errors.isEmpty()) {
128	            importErrorRepository.saveAll(errors);
129	        }
130	
131	        job.setTotalRows(totalRows);
132	        job.setSuccessCount(successCount);
133	        job.setErrorCount(errors.size());
134	        job.setStatus(ImportJob.JobStatus.COMPLETED);
135	        job.setCompletedAt(LocalDateTime.now());
136	        importJobRepository.save(job);
137	
138	        log.info("Import job {} completed: {} success, {} errors out of {} rows",
139	                job.getId(), successCount, errors.size(), totalRows);
140	
141	        return toResponse(job, errors);
142	    }
