144	    private List<String[]> parseCsv(InputStream inputStream) throws Exception {
145	        List<String[]> rows = new ArrayList<>();
146	        try (CSVReader csvReader = new CSVReaderBuilder(new InputStreamReader(inputStream))
147	                .withSkipLines(1)  // skip header
148	                .build()) {
149	            String[] row;
150	            while ((row = csvReader.readNext()) != null) {
151	                if (row.length > 0 && !String.join("", row).trim().isEmpty()) {
152	                    rows.add(row);
153	                }
154	            }
155	        }
156	        return rows;
157	    }
158	
159	    private List<String[]> parseExcel(InputStream inputStream) throws Exception {
160	        List<String[]> rows = new ArrayList<>();
161	        try (Workbook workbook = new XSSFWorkbook(inputStream)) {
162	            Sheet sheet = workbook.getSheetAt(0);
163	            DataFormatter formatter = new DataFormatter();
164	            boolean headerSkipped = false;
165	            for (Row row : sheet) {
166	                if (!headerSkipped) {
167	                    headerSkipped = true;
168	                    continue;
169	                }
170	                int lastCell = row.getLastCellNum();
171	                if (lastCell <= 0) continue;
172	                String[] fields = new String[lastCell];
173	                for (int i = 0; i < lastCell; i++) {
174	                    Cell cell = row.getCell(i, Row.MissingCellPolicy.CREATE_NULL_AS_BLANK);
175	                    fields[i] = formatter.formatCellValue(cell);
176	                }
177	                if (fields.length > 0 && !fields[0].trim().isEmpty()) {
178	                    rows.add(fields);
179	                }
180	            }
181	        }
182	        return rows;
183	    }
184	
185	    private void persistEntity(String entityType, String code, String name,
186	                                String[] fields, Long userId) {
187	        LocalDate effectiveFrom;
188	        if (fields.length > 2 && !fields[2].trim().isEmpty()) {
189	            effectiveFrom = parseDate(fields[2].trim(), "effectiveFrom");
190	        } else {
191	            effectiveFrom = LocalDate.now();
192	        }
193	
194	        MasterDataRequest request = MasterDataRequest.builder()
195	                .code(code)
196	                .name(name)
197	                .effectiveFrom(effectiveFrom)
198	                .build();
199	
200	        switch (entityType.toUpperCase()) {
201	            case "TERM":
202	                if (fields.length > 3 && !fields[3].trim().isEmpty()) {
203	                    request.setStartDate(parseDate(fields[3].trim(), "startDate"));
204	                }
205	                if (fields.length > 4 && !fields[4].trim().isEmpty()) {
206	                    request.setEndDate(parseDate(fields[4].trim(), "endDate"));
207	                }
208	                termService.create(request, userId);
209	                break;
210	            case "SCHOOL":
211	                schoolService.create(request, userId);
212	                break;
213	            case "MAJOR":
214	                if (fields.length > 3 && !fields[3].trim().isEmpty()) {
215	                    request.setSchoolId(parseId(fields[3].trim(), "schoolId"));
216	                }
217	                majorService.create(request, userId);
218	                break;
219	            case "CLASS":
220	                if (fields.length > 3 && !fields[3].trim().isEmpty()) {
221	                    request.setMajorId(parseId(fields[3].trim(), "majorId"));
222	                }
223	                classService.create(request, userId);
224	                break;
225	            case "COURSE":
226	                if (fields.length > 3 && !fields[3].trim().isEmpty()) {
227	                    request.setClassId(parseId(fields[3].trim(), "classId"));
228	                }
229	                if (fields.length > 4 && !fields[4].trim().isEmpty()) {
230	                    request.setTermId(parseId(fields[4].trim(), "termId"));
231	                }
232	                courseService.create(request, userId);
233	                break;
234	            default:
235	                throw new IllegalArgumentException("Unknown entity type: " + entityType);
236	        }
237	    }
238	
239	    private LocalDate parseDate(String value, String fieldName) {
240	        // Accept ISO format (yyyy-MM-dd) first, then US format (MM/dd/yyyy)
241	        try {
242	            return LocalDate.parse(value, DATE_FORMAT_ISO);
243	        } catch (DateTimeParseException ignored) {
244	        }
245	        try {
246	            return LocalDate.parse(value, DATE_FORMAT_US);
247	        } catch (DateTimeParseException e) {
248	            throw new IllegalArgumentException(
249	                    "Invalid date format for " + fieldName + ": '" + value + "' (expected yyyy-MM-dd or MM/dd/yyyy)");
250	        }
251	    }
252	
253	    private Long parseId(String value, String fieldName) {
254	        try {
255	            return Long.parseLong(value);
256	        } catch (NumberFormatException e) {
257	            throw new IllegalArgumentException(
258	                    "Invalid numeric ID for " + fieldName + ": '" + value + "'");
259	        }
260	    }
261	
262	    @Transactional(readOnly = true)
263	    public ImportJobResponse getJobById(Long jobId) {
264	        ImportJob job = importJobRepository.findById(jobId)
265	                .orElseThrow(() -> new ResourceNotFoundException("ImportJob", jobId));
266	        List<ImportError> errors = importErrorRepository.findByJobId(jobId);
267	        return toResponse(job, errors);
268	    }
269	
270	    private ImportError buildError(Long jobId, int rowNum, String field, String message, String rawValue) {
271	        return ImportError.builder()
272	                .jobId(jobId)
273	                .rowNumber(rowNum)
274	                .field(field)
275	                .message(message)
276	                .rawValue(rawValue)
277	                .build();
278	    }
279	
280	    private ImportJobResponse toResponse(ImportJob job, List<ImportError> errors) {
281	        List<ImportJobResponse.ImportErrorResponse> errorResponses = errors.stream()
282	                .map(e -> ImportJobResponse.ImportErrorResponse.builder()
283	                        .rowNumber(e.getRowNumber())
284	                        .field(e.getField())
285	                        .message(e.getMessage())
286	                        .rawValue(e.getRawValue())
287	                        .build())
288	                .collect(Collectors.toList());
289	
290	        return ImportJobResponse.builder()
291	                .id(job.getId())
292	                .fileName(job.getFileName())
293	                .entityType(job.getEntityType())
294	                .totalRows(job.getTotalRows())
295	                .successCount(job.getSuccessCount())
296	                .errorCount(job.getErrorCount())
297	                .status(job.getStatus())
298	                .createdAt(job.getCreatedAt())
299	                .completedAt(job.getCompletedAt())
300	                .errors(errorResponses)
301	                .build();
302	    }
303	}
