14	import java.math.RoundingMode;
15	import java.time.LocalDateTime;
16	import java.util.List;
17	
18	@Service
19	public class DiscrepancyService {
20	
21	    private static final BigDecimal VARIANCE_THRESHOLD_PERCENT = new BigDecimal("2.00");
22	    private static final BigDecimal VARIANCE_THRESHOLD_UNITS = new BigDecimal("5.00");
23	
24	    private final DiscrepancyRepository discrepancyRepository;
25	    private final InboundReceiptRepository receiptRepository;
26	
27	    public DiscrepancyService(DiscrepancyRepository discrepancyRepository,
28	                              InboundReceiptRepository receiptRepository) {
29	        this.discrepancyRepository = discrepancyRepository;
30	        this.receiptRepository = receiptRepository;
31	    }
32	
33	    /**
34	     * Auto-detect discrepancy when received qty differs from expected qty.
35	     * Creates a discrepancy record if variance > 2% or > 5 units.
36	     * Sets supervisorRequired=true if those thresholds are exceeded.
37	     */
38	    @Transactional
39	    public Discrepancy detectAndCreate(InboundLine line) {
40	        BigDecimal expected = line.getExpectedQty();
41	        BigDecimal actual = line.getReceivedQty();
42	        BigDecimal difference = actual.subtract(expected).abs();
43	
44	        if (expected.compareTo(BigDecimal.ZERO) == 0) {
45	            return null;
46	        }
47	
48	        BigDecimal variancePercent = difference
49	                .divide(expected, 4, RoundingMode.HALF_UP)
50	                .multiply(BigDecimal.valueOf(100))
51	                .setScale(2, RoundingMode.HALF_UP);
52	
53	        boolean exceedsPercentThreshold = variancePercent.compareTo(VARIANCE_THRESHOLD_PERCENT) > 0;
54	        boolean exceedsUnitThreshold = difference.compareTo(VARIANCE_THRESHOLD_UNITS) > 0;
55	
56	        if (!exceedsPercentThreshold && !exceedsUnitThreshold) {
57	            return null; // No discrepancy
58	        }
59	
60	        boolean supervisorRequired = exceedsPercentThreshold || exceedsUnitThreshold;
61	
62	        Discrepancy discrepancy = Discrepancy.builder()
63	                .receiptId(line.getReceiptId())
64	                .lineId(line.getId())
65	                .discrepancyType(Discrepancy.DiscrepancyType.QUANTITY)
66	                .expectedValue(expected)
67	                .actualValue(actual)
68	                .variancePercent(variancePercent)
69	                .supervisorRequired(supervisorRequired)
70	                .build();
71	
72	        // Flag the receipt as needing supervisor approval
73	        if (supervisorRequired) {
74	            InboundReceipt receipt = receiptRepository.findById(line.getReceiptId())
75	                    .orElseThrow(() -> new ResourceNotFoundException("InboundReceipt", line.getReceiptId()));
76	            receipt.setSupervisorApprovalRequired(true);
77	            receiptRepository.save(receipt);
78	        }
79	
80	        return discrepancyRepository.save(discrepancy);
81	    }
82	
83	    @Transactional
84	    public Discrepancy resolve(Long receiptId, Long discrepancyId, Long resolvedBy, Discrepancy.ReasonCode reasonCode, String notes) {
85	        Discrepancy discrepancy = discrepancyRepository.findById(discrepancyId)
86	                .orElseThrow(() -> new ResourceNotFoundException("Discrepancy", discrepancyId));
87	
88	        if (!discrepancy.getReceiptId().equals(receiptId)) {
89	            throw new BusinessException("Discrepancy does not belong to the specified receipt");
90	        }
91	
92	        if (discrepancy.getResolvedBy() != null) {
93	            throw new BusinessException("Discrepancy has already been resolved");
94	        }
95	
96	        discrepancy.setResolvedBy(resolvedBy);
97	        discrepancy.setResolvedAt(LocalDateTime.now());
98	        discrepancy.setReasonCode(reasonCode);
99	        discrepancy.setNotes(notes);
100	
101	        return discrepancyRepository.save(discrepancy);
102	    }
103	
104	    @Transactional(readOnly = true)
105	    public List<Discrepancy> getByReceiptId(Long receiptId) {
106	        return discrepancyRepository.findByReceiptId(receiptId);
107	    }
108	}
