51	    @Transactional
52	    @SuppressWarnings("unchecked")
53	    public String importAccountData(Long userId, Map<String, Object> data) {
54	        int studyCount = 0;
55	        int fitnessCount = 0;
56	        int goalCount = 0;
57	        int checkInCount = 0;
58	
59	        // Restore profile metadata if present
60	        if (data.containsKey("profileData")) {
61	            try {
62	                Map<String, Object> profile = (Map<String, Object>) data.get("profileData");
63	                restoreProfile(userId, profile);
64	            } catch (Exception e) {
65	                log.warn("Failed to restore profile metadata: {}", e.getMessage());
66	            }
67	        }
68	
69	        // Import study data if present
70	        if (data.containsKey("studyData")) {
71	            try {
72	                StudyExportData studyData = objectMapper.convertValue(data.get("studyData"), StudyExportData.class);
73	                studyExportImportService.importData(userId, studyData);
74	                studyCount++;
75	            } catch (Exception e) {
76	                log.warn("Failed to import study data: {}", e.getMessage());
77	            }
78	        }
79	
80	        // Import fitness assessments if present
81	        if (data.containsKey("fitnessData")) {
82	            try {
83	                List<Map<String, Object>> fitnessDataList = (List<Map<String, Object>>) data.get("fitnessData");
84	                for (Map<String, Object> assessmentData : fitnessDataList) {
85	                    AssessmentRequest request = objectMapper.convertValue(assessmentData, AssessmentRequest.class);
86	                    assessmentService.createOrUpdate(userId, request);
87	                    fitnessCount++;
88	                }
89	            } catch (Exception e) {
