120	                for (Map<String, Object> checkInData : checkInsDataList) {
121	                    Long oldGoalId = checkInData.get("goalId") != null
122	                            ? ((Number) checkInData.get("goalId")).longValue() : null;
123	                    if (oldGoalId == null) continue;
124	
