231	    private byte[] encryptWithPassword(byte[] data, String password) {
232	        try {
233	            SecureRandom random = new SecureRandom();
234	            byte[] salt = new byte[16];
235	            random.nextBytes(salt);
236	            byte[] iv = new byte[16];
237	            random.nextBytes(iv);
238	
239	            SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
240	            PBEKeySpec spec = new PBEKeySpec(password.toCharArray(), salt, 65536, 256);
241	            SecretKeySpec keySpec = new SecretKeySpec(factory.generateSecret(spec).getEncoded(), "AES");
242	
243	            Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
244	            cipher.init(Cipher.ENCRYPT_MODE, keySpec, new IvParameterSpec(iv));
245	            byte[] encrypted = cipher.doFinal(data);
246	
247	            // Prepend salt + IV to encrypted data
248	            byte[] result = new byte[salt.length + iv.length + encrypted.length];
249	            System.arraycopy(salt, 0, result, 0, salt.length);
250	            System.arraycopy(iv, 0, result, salt.length, iv.length);
251	            System.arraycopy(encrypted, 0, result, salt.length + iv.length, encrypted.length);
252	            return result;
253	        } catch (Exception e) {
254	            throw new BusinessException("Failed to encrypt export file: " + e.getMessage());
255	        }
256	    }
257	
258	    @SuppressWarnings("unchecked")
259	    public java.util.Map<String, Object> decryptExportFile(byte[] fileBytes, String password) {
260	        try {
261	            byte[] decrypted = decryptWithPassword(fileBytes, password);
262	            String json = new String(decrypted, java.nio.charset.StandardCharsets.UTF_8);
263	            return objectMapper.readValue(json, java.util.Map.class);
264	        } catch (Exception e) {
265	            throw new BusinessException("Failed to decrypt export file. Check that the password is correct.");
266	        }
267	    }
268	
269	    private byte[] decryptWithPassword(byte[] data, String password) {
270	        try {
271	            byte[] salt = new byte[16];
272	            byte[] iv = new byte[16];
273	            System.arraycopy(data, 0, salt, 0, 16);
274	            System.arraycopy(data, 16, iv, 0, 16);
275	            byte[] encrypted = new byte[data.length - 32];
276	            System.arraycopy(data, 32, encrypted, 0, encrypted.length);
277	
278	            SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
279	            PBEKeySpec spec = new PBEKeySpec(password.toCharArray(), salt, 65536, 256);
280	            SecretKeySpec keySpec = new SecretKeySpec(factory.generateSecret(spec).getEncoded(), "AES");
281	
282	            Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
283	            cipher.init(Cipher.DECRYPT_MODE, keySpec, new IvParameterSpec(iv));
284	            return cipher.doFinal(encrypted);
285	        } catch (Exception e) {
286	            throw new BusinessException("Decryption failed: " + e.getMessage());
287	        }
288	    }
