52	                .userId(userId)
53	                .status(DeletionRequest.DeletionStatus.PENDING)
54	                .build();
55	
56	        request = deletionRequestRepository.save(request);
57	
58	        // Process immediately
59	        processDeletion(request);
60	
61	        return request;
62	    }
