  14	import java.math.RoundingMode;
  15	import java.time.LocalDateTime;
  16	import java.util.List;
  17	
  18	@Service
  19	public class DiscrepancyService {
  20	
  21	    private static final BigDecimal VARIANCE_THRESHOLD_PERCENT = new BigDecimal("2.00");
  22	    private static final BigDecimal VARIANCE_THRESHOLD_UNITS = new BigDecimal("5.00");
  23	
  24	    private final DiscrepancyRepository discrepancyRepository;
  25	    private final InboundReceiptRepository receiptRepository;
  26	
  27	    public DiscrepancyService(DiscrepancyRepository discrepancyRepository,
  28	                              InboundReceiptRepository receiptRepository) {
  29	        this.discrepancyRepository = discrepancyRepository;
  30	        this.receiptRepository = receiptRepository;
  31	    }
  32	
  33	    /**
  34	     * Auto-detect discrepancy when received qty differs from expected qty.
  35	     * Creates a discrepancy record if variance > 2% or > 5 units.
  35	     * Sets supervisorRequired=true if those thresholds are exceeded.
  36	     */
  37	    @Transactional
  38	    public Discrepancy detectAndCreate(InboundLine line) {
  39	        BigDecimal expected = line.getExpectedQty();
  39	        BigDecimal actual = line.getReceivedQty();
  40	        BigDecimal difference = actual.subtract(expected).abs();
  41	
  42	        if (expected.compareTo(BigDecimal.ZERO) == 0) {
  42	            return null;
  43	        }
  44	
  45	        BigDecimal variancePercent = difference
  45	            .divide(expected, 4, RoundingMode.HALF_UP)
  46	            .multiply(BigDecimal.valueOf(100))
  47	            .setScale(2, RoundingMode.HALF_UP);
  48	
  49	        boolean exceedsPercentThreshold = variancePercent.compareTo(VARIANCE_THRESHOLD_PERCENT) > 0;
  49	        boolean exceedsUnitThreshold = difference.compareTo(VARIANCE_THRESHOLD_UNITS) > 0;
  50	
  51	        if (!exceedsPercentThreshold && !exceedsUnitThreshold) {
  51	            return null; // No discrepancy
  52	        }
  53	
  54        boolean supervisorRequired = exceedsPercentThreshold || exceedsUnitThreshold;
  54	
  55        Discrepancy discrepancy = Discrepancy.builder()
  55            .receiptId(line.getReceiptId())
  56            .lineId(line.getId())
  56            .discrepancyType(Discrepancy.DiscrepancyType.QUANTITY)
  57            .expectedValue(expected)
  57            .actualValue(actual)
  58            .variancePercent(variancePercent)
  58            .supervisorRequired(supervisorRequired)
  59            .build();
  60	
  61        // Flag the receipt as needing supervisor approval
  61        if (supervisorRequired) {
  62            InboundReceipt receipt = receiptRepository.findById(line.getReceiptId())
  62                .orElseThrow(() -> new ResourceNotFoundException("InboundReceipt", line.getReceiptId()));
  63            receipt.setSupervisorApprovalRequired(true);
  63            receiptRepository.save(receipt);
  64        }
  65	
  66        return discrepancyRepository.save(discrepancy);
  66    }
