1	package com.campusfit.inbound.service;
2	
3	import com.campusfit.inbound.dto.InboundLineResponse;
4	import com.campusfit.inbound.dto.InboundReceiptRequest;
5	import com.campusfit.inbound.dto.InboundReceiptResponse;
6	import com.campusfit.inbound.entity.InboundLine;
7	import com.campusfit.inbound.entity.InboundReceipt;
8	import com.campusfit.inbound.repository.InboundLineRepository;
9	import com.campusfit.inbound.repository.InboundReceiptRepository;
10	import com.campusfit.shared.exception.ResourceNotFoundException;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.util.List;
15	import java.util.UUID;
16	import java.util.stream.Collectors;
17	
18	@Service
19	public class InboundReceiptService {
20	
21	    private final InboundReceiptRepository receiptRepository;
22	    private final InboundLineRepository lineRepository;
23	
24	    public InboundReceiptService(InboundReceiptRepository receiptRepository,
25	                                 InboundLineRepository lineRepository) {
26	        this.receiptRepository = receiptRepository;
27	        this.lineRepository = lineRepository;
28	    }
29	
30	    @Transactional
31	    public InboundReceiptResponse create(Long userId, InboundReceiptRequest request) {
32	        String receiptNumber = "RCV-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
33	
34	        InboundReceipt receipt = InboundReceipt.builder()
35	                .receiptNumber(receiptNumber)
36	                .receiptType(request.getReceiptType())
37	                .referenceNumber(request.getReferenceNumber())
38	                .supplierName(request.getSupplierName())
39	                .status(InboundReceipt.ReceiptStatus.DRAFT)
40	                .expectedDate(request.getExpectedDate())
41	                .createdBy(userId)
42	                .build();
43	
44	        InboundReceipt saved = receiptRepository.save(receipt);
45	        return toResponse(saved, List.of());
46	    }
47	
48	    @Transactional(readOnly = true)
49	    public InboundReceiptResponse getById(Long receiptId) {
50	        InboundReceipt receipt = receiptRepository.findById(receiptId)
51	                .orElseThrow(() -> new ResourceNotFoundException("InboundReceipt", receiptId));
52	
53	        List<InboundLine> lines = lineRepository.findByReceiptId(receiptId);
54	        return toResponse(receipt, lines);
55	    }
56	
57	    @Transactional(readOnly = true)
58	    public List<InboundReceiptResponse> list(InboundReceipt.ReceiptStatus status) {
59	        List<InboundReceipt> receipts;
60	        if (status != null) {
61	            receipts = receiptRepository.findByStatus(status);
62	        } else {
63	            receipts = receiptRepository.findAll();
64	        }
65	
66	        return receipts.stream()
67	                .map(r -> {
68	                    List<InboundLine> lines = lineRepository.findByReceiptId(r.getId());
69	                    return toResponse(r, lines);
70	                })
71	                .collect(Collectors.toList());
72	    }
73	
74	    private InboundReceiptResponse toResponse(InboundReceipt r, List<InboundLine> lines) {
75	        List<InboundLineResponse> lineResponses = lines.stream()
76	                .map(this::toLineResponse)
77	                .collect(Collectors.toList());
78	
79	        return InboundReceiptResponse.builder()
80	                .id(r.getId())
81	                .receiptNumber(r.getReceiptNumber())
82	                .receiptType(r.getReceiptType())
83	                .referenceNumber(r.getReferenceNumber())
84	                .supplierName(r.getSupplierName())
85	                .status(r.getStatus())
86	                .expectedDate(r.getExpectedDate())
87	                .receivedDate(r.getReceivedDate())
88	                .createdBy(r.getCreatedBy())
89	                .supervisorApprovalRequired(r.isSupervisorApprovalRequired())
90	                .supervisorApprovedBy(r.getSupervisorApprovedBy())
