64	    @Transactional
65	    public void processDeletion(DeletionRequest request) {
66	        request.setStatus(DeletionRequest.DeletionStatus.PROCESSING);
67	        deletionRequestRepository.save(request);
68	
69	        Long userId = request.getUserId();
70	
71	        User user = userRepository.findById(userId)
72	                .orElseThrow(() -> new ResourceNotFoundException("User", userId));
73	
74	        // Hard-delete all personal data records
75	        checkInRepository.deleteByUserId(userId);
76	        goalRepository.deleteByUserId(userId);
77	        assessmentRepository.deleteByUserId(userId);
78	        studyPlanRepository.deleteByUserId(userId);
79	
80	        // Delete all sessions for this user
81	        sessionRepository.deleteByUserId(userId);
82	
83	        // Hard-delete the user row itself.
84	        // Non-cascading FK references (inbound receipts, notifications, deletion requests)
85	        // are configured with ON DELETE SET NULL via V17 migration, so they become
86	        // de-identified audit artifacts with created_by/user_id = NULL.
87	        userRepository.delete(user);
88	
89	        // Mark deletion complete
90	        request.setStatus(DeletionRequest.DeletionStatus.COMPLETED);
91	        request.setProcessedAt(LocalDateTime.now());
92	        deletionRequestRepository.save(request);
93	
94	        log.info("Account deletion completed for user={}", "***" + (userId % 1000));
95	    }
96	}
