1	package com.campusfit.auth.service;
2	
3	import com.campusfit.auth.dto.*;
4	import com.campusfit.auth.entity.*;
5	import com.campusfit.auth.mapper.AuthMapper;
6	import com.campusfit.auth.repository.*;
7	import com.campusfit.shared.exception.BusinessException;
8	import com.campusfit.shared.exception.ResourceNotFoundException;
9	import com.campusfit.shared.security.UserPrincipal;
10	import org.springframework.beans.factory.annotation.Value;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.time.LocalDateTime;
15	import java.util.List;
16	import java.util.Set;
17	import java.util.UUID;
18	import java.util.stream.Collectors;
19	
20	@Service
21	public class AuthService {
22	
23	    private final UserRepository userRepository;
24	    private final RoleRepository roleRepository;
25	    private final UserRoleRepository userRoleRepository;
26	    private final SessionRepository sessionRepository;
27	    private final PasswordService passwordService;
28	    private final LoginAttemptService loginAttemptService;
29	    private final AuthMapper authMapper;
30	    private final int sessionTimeoutMinutes;
31	
32	    public AuthService(UserRepository userRepository,
33	                       RoleRepository roleRepository,
34	                       UserRoleRepository userRoleRepository,
35	                       SessionRepository sessionRepository,
36	                       PasswordService passwordService,
37	                       LoginAttemptService loginAttemptService,
38	                       AuthMapper authMapper,
39	                       @Value("${app.session.timeout-minutes:30}") int sessionTimeoutMinutes) {
40	        this.userRepository = userRepository;
41	        this.roleRepository = roleRepository;
42	        this.userRoleRepository = userRoleRepository;
43	        this.sessionRepository = sessionRepository;
44	        this.passwordService = passwordService;
45	        this.loginAttemptService = loginAttemptService;
46	        this.authMapper = authMapper;
47	        this.sessionTimeoutMinutes = sessionTimeoutMinutes;
48	    }
49	
50	    @Transactional
51	    public UserDto signUp(SignUpRequest request) {
52	        if (userRepository.existsByUsername(request.getUsername())) {
53	            throw new BusinessException("Username already exists: " + request.getUsername());
54	        }
55	
56	        User user = User.builder()
57	            .username(request.getUsername())
58	            .passwordHash(passwordService.encode(request.getPassword()))
59	            .email(request.getEmail())
60	            .phone(request.getPhone())
61	            .status(User.UserStatus.ACTIVE)
62	            .failedAttempts(0)
63	            .build();
64	
65	        user = userRepository.save(user);
66	
67	        Role role = roleRepository.findByCode("REGULAR_USER")
68	            .orElseThrow(() -> new BusinessException("Role not found: REGULAR_USER"));
69	
70	        UserRole userRole = UserRole.builder()
71	            .userId(user.getId())
72	            .roleId(role.getId())
73	            .assignedAt(LocalDateTime.now())
74	            .build();
75	        userRoleRepository.save(userRole);
76	
77	        List<String> roles = List.of(role.getCode());
78	        return authMapper.toUserDto(user, roles);
79	    }
80	
81	    @Transactional
82	    public LoginResponse signIn(LoginRequest request, String ipAddress, String userAgent) {
83	        User user = userRepository.findByUsername(request.getUsername())
84	            .orElseThrow(() -> new BusinessException("Invalid username or password"));
85	
86	        if (user.getStatus() == User.UserStatus.DISABLED || user.getStatus() == User.UserStatus.DELETED) {
87	            throw new BusinessException("Account is not active");
88	        }
89	
90	        if (loginAttemptService.isLocked(user)) {
91	            throw new BusinessException("Account is locked due to too many failed attempts. Please try again later.");
92	        }
93	
94	        if (!passwordService.matches(request.getPassword(), user.getPasswordHash())) {
95	            loginAttemptService.recordFailedAttempt(user);
96	            throw new BusinessException("Invalid username or password");
97	        }
98	
99	        loginAttemptService.resetAttempts(user);
100	
101	        String token = UUID.randomUUID().toString();
102	        LocalDateTime expiresAt = LocalDateTime.now().plusMinutes(sessionTimeoutMinutes);
103	
104	        Session session = Session.builder()
105	            .userId(user.getId())
106	            .token(token)
107	            .ipAddress(ipAddress)
108	            .userAgent(userAgent)
109	            .expiresAt(expiresAt)
110	            .lastAccessedAt(LocalDateTime.now())
111	            .build();
112	        sessionRepository.save(session);
113	
114	        List<String> roles = getUserRoleCodes(user.getId());
115	        UserDto userDto = authMapper.toUserDto(user, roles);
116	
117	        return LoginResponse.builder()
118	            .token(token)
119	            .user(userDto)
120	            .expiresAt(expiresAt)
121	            .build();
122	    }
123	
124	    @Transactional
125	    public void signOut(String token) {
126	        Session session = sessionRepository.findByToken(token)
127	            .orElseThrow(() -> new BusinessException("Invalid session token"));
128	        sessionRepository.delete(session);
129	    }
130	
131	    @Transactional(readOnly = true)
132	    public UserPrincipal validateSession(String token) {
133	        Session session = sessionRepository.findByToken(token)
134	            .orElse(null);
135	
136	        if (session == null) {
137	            return null;
138	        }
139	
140	        LocalDateTime lastActivity = session.getLastAccessedAt() != null
141	            ? session.getLastAccessedAt() : session.getCreatedAt();
142	        if (lastActivity == null || lastActivity.plusMinutes(sessionTimeoutMinutes).isBefore(LocalDateTime.now())) {
143	            return null;
144	        }
145	
146	        User user = userRepository.findById(session.getUserId())
147	            .orElse(null);
148	
149	        if (user == null) {
150	            return null;
151	        }
152	
153	        Set<String> roles = getUserRoleCodes(user.getId()).stream()
154	            .collect(Collectors.toSet());
155	
156	        return new UserPrincipal(user.getId(), user.getUsername(), roles);
157	    }
158	
159	    @Transactional(readOnly = true)
160	    public UserDto getCurrentUser(Long userId) {
161	        User user = userRepository.findById(userId)
162	            .orElseThrow(() -> new ResourceNotFoundException("User", userId));
163	
164	        List<String> roles = getUserRoleCodes(userId);
165	        return authMapper.toUserDto(user, roles);
166	    }
167	
168	    @Transactional
169	    public UserDto assignRole(Long userId, String roleCode) {
170	        User user = userRepository.findById(userId)
171	            .orElseThrow(() -> new ResourceNotFoundException("User", userId));
172	
173	        Role role = roleRepository.findByCode(roleCode)
174	            .orElseThrow(() -> new BusinessException("Role not found: " + roleCode));
175	
176	        boolean alreadyAssigned = userRoleRepository.findByUserId(userId).stream()
177	            .anyMatch(ur -> ur.getRoleId().equals(role.getId()));
178	
179	        if (!alreadyAssigned) {
180	            UserRole userRole = UserRole.builder()
181	                .userId(userId)
182	                .roleId(role.getId())
183	                .assignedAt(LocalDateTime.now())
184	                .build();
185	            userRoleRepository.save(userRole);
186	        }
187	
188	        List<String> roles = getUserRoleCodes(userId);
189	        return authMapper.toUserDto(user, roles);
190	    }
191	
192	    private List<String> getUserRoleCodes(Long userId) {
193	        List<UserRole> userRoles = userRoleRepository.findByUserId(userId);
194	        return userRoles.stream()
195	            .map(ur -> roleRepository.findById(ur.getRoleId())
196	                .map(Role::getCode)
197	                .orElse(null))
198	            .filter(code -> code != null)
199	            .collect(Collectors.toList());
200	    }
201	}
