21	
22	    private final AuthService authService;
23	
24	    public AuthController(AuthService authService) {
25	        this.authService = authService;
26	    }
27	
28	    @PostMapping("/auth/sign-up")
29	    public ResponseEntity<ApiResponse<UserDto>> signUp(@Valid @RequestBody SignUpRequest request) {
30	        UserDto user = authService.signUp(request);
31	        return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.ok(user));
32	    }
33	
34	    @PostMapping("/auth/sign-in")
35	    public ResponseEntity<ApiResponse<LoginResponse>> signIn(@Valid @RequestBody LoginRequest request,
36	                                                              HttpServletRequest httpRequest) {
37	        String ipAddress = getClientIpAddress(httpRequest);
38	        String userAgent = httpRequest.getHeader("User-Agent");
39	
40	        LoginResponse response = authService.signIn(request, ipAddress, userAgent);
41	        return ResponseEntity.ok(ApiResponse.ok(response));
42	    }
43	
44	    @PostMapping("/auth/sign-out")
45	    public ResponseEntity<ApiResponse<Void>> signOut(HttpServletRequest request) {
46	        String token = extractToken(request);
47	        if (StringUtils.hasText(token)) {
48	            authService.signOut(token);
49	        }
50	        return ResponseEntity.ok(ApiResponse.ok(null));
51	    }
52	
53	    @GetMapping("/me")
54	    public ResponseEntity<ApiResponse<UserDto>> getCurrentUser() {
55	        Long userId = SecurityContextHelper.getCurrentUserId();
56	        UserDto user = authService.getCurrentUser(userId);
57	        return ResponseEntity.ok(ApiResponse.ok(user));
58	    }
59	
60	    @PreAuthorize("hasRole('ADMIN')")
61	    @PostMapping("/admin/users/{userId}/roles")
62	    public ResponseEntity<ApiResponse<UserDto>> assignRole(@PathVariable Long userId,
63	                                                            @RequestParam String roleCode) {
64	        UserDto user = authService.assignRole(userId, roleCode);
65	        return ResponseEntity.ok(ApiResponse.ok(user));
66	    }
67	
68	    private String extractToken(HttpServletRequest request) {
69	        String bearerToken = request.getHeader("Authorization");
70	        if (StringUtils.hasText(bearerToken) && bearerToken.startsWith("Bearer ")) {
71	            return bearerToken.substring(7);
72	        }
73	        return null;
74	    }
75	
76	    private String getClientIpAddress(HttpServletRequest request) {
77	        String xForwardedFor = request.getHeader("X-Forwarded-For");
78	        if (StringUtils.hasText(xForwardedFor)) {
79	            return xForwardedFor.split(",")[0].trim();
80	        }
81	        return request.getRemoteAddr();
82	    }
83	}
