2	
3	import com.campusfit.fitness.entity.Goal;
4	import com.campusfit.fitness.entity.GoalAdjustmentAudit;
5	import com.campusfit.fitness.repository.GoalAdjustmentAuditRepository;
6	import com.campusfit.fitness.repository.GoalRepository;
7	import org.springframework.stereotype.Component;
8	import org.springframework.transaction.annotation.Transactional;
9	
10	import java.math.BigDecimal;
11	import java.math.RoundingMode;
12	import java.time.LocalDate;
13	import java.time.temporal.ChronoUnit;
14	
15	@Component
16	public class GoalRecalculationPolicy {
17	
18	    private final GoalRepository goalRepository;
19	    private final GoalAdjustmentAuditRepository auditRepository;
20	
21	    public GoalRecalculationPolicy(GoalRepository goalRepository,
22	                                   GoalAdjustmentAuditRepository auditRepository) {
23	        this.goalRepository = goalRepository;
24	        this.auditRepository = auditRepository;
25	    }
26	
27	    /**
28	     * When 2 consecutive check-ins are missed:
29	     * - Extend targetDate by 20% of remaining duration
30	     * - Reduce weekly target by 10%
31	     * - Create GoalAdjustmentAudit record
32	     * - Reset missedCheckIns counter
33	     */
34	    @Transactional
35	    public void recalculate(Goal goal, Long adjustedBy) {
36	        BigDecimal previousTarget = goal.getTargetValue();
37	        LocalDate previousTargetDate = goal.getTargetDate();
38	
39	        // Calculate remaining duration
40	        long remainingDays = ChronoUnit.DAYS.between(LocalDate.now(), goal.getTargetDate());
41	        if (remainingDays <= 0) {
42	            remainingDays = 7; // minimum fallback
43	        }
44	
45	        // Extend target date by 20% of remaining duration
46	        long extensionDays = Math.max(1, (long) (remainingDays * 0.20));
47	        LocalDate newTargetDate = goal.getTargetDate().plusDays(extensionDays);
48	
49	        // Reduce target by 10% (move target closer to current value)
50	        BigDecimal difference = goal.getTargetValue().subtract(goal.getCurrentValue());
51	        BigDecimal reduction = difference.multiply(BigDecimal.valueOf(0.10));
52	        BigDecimal newTarget = goal.getTargetValue().subtract(reduction).setScale(2, RoundingMode.HALF_UP);
53	
54	        goal.setTargetDate(newTargetDate);
55	        goal.setTargetValue(newTarget);
56	        goal.setMissedCheckIns(0);
57	        goal.setStatus(Goal.GoalStatus.RECALCULATED);
58	        goalRepository.save(goal);
59	
60	        // Create audit record
61	        GoalAdjustmentAudit audit = GoalAdjustmentAudit.builder()
62	                .goalId(goal.getId())
63	                .previousTarget(previousTarget)
64	                .newTarget(newTarget)
65	                .previousTargetDate(previousTargetDate)
66	                .newTargetDate(newTargetDate)
67	                .reason("Auto-recalculated due to 2 consecutive missed check-ins. " +
68	                        "Extended deadline by " + extensionDays + " days, reduced target by 10%.")
69	                .adjustedBy(adjustedBy)
70	                .build();
71	        auditRepository.save(audit);
72	    }
73	}
