8	    public String mask(String value) {
9	        if (value == null) {
10	            return null;
11	        }
12	        int length = value.length();
13	        if (length <= 4) {
14	            return "***";
15	        }
16	        String first = value.substring(0, 2);
17	        String last = value.substring(length - 2);
18	        return first + "***" + last;
19	    }
