28	    public String maskEmail(String email) {
29	        if (email == null || email.isEmpty()) {
30	            return null;
31	        }
32	        int atIndex = email.indexOf('@');
33	        if (atIndex <= 1) {
34	            return "***@" + (atIndex >= 0 ? email.substring(atIndex + 1) : "***");
35	        }
36	        return email.charAt(0) + "***@" + email.substring(atIndex + 1);
37	    }
