23	@Service
24	public class StudyExportImportService {
25	
26	    private final StudyPlanRepository studyPlanRepository;
27	    private final DailyCompletionRepository completionRepository;
28	    private final ForgettingPointRepository forgettingPointRepository;
29	    private final ObjectMapper objectMapper;
30	
31	    public StudyExportImportService(StudyPlanRepository studyPlanRepository,
32	                                    DailyCompletionRepository completionRepository,
33	                                    ForgettingPointRepository forgettingPointRepository) {
34	        this.studyPlanRepository = studyPlanRepository;
35	        this.completionRepository = completionRepository;
36	        this.forgettingPointRepository = forgettingPointRepository;
37	        this.objectMapper = new ObjectMapper();
38	        this.objectMapper.registerModule(new JavaTimeModule());
39	    }
40	
41	    @Transactional(readOnly = true)
42	    public StudyExportData exportData(Long userId) {
43	        List<StudyPlan> plans = studyPlanRepository.findByUserId(userId);
44	
45	        List<StudyPlanResponse> planResponses = plans.stream()
46	                .map(this::toPlanResponse)
47	                .collect(Collectors.toList());
48	
49	        List<DailyCompletionResponse> completionResponses = new ArrayList<>();
50	        List<ForgettingPointResponse> fpResponses = new ArrayList<>();
51	
52	        for (StudyPlan plan : plans) {
53	            completionRepository.findByPlanId(plan.getId()).stream()
54	                    .map(this::toCompletionResponse)
55	                    .forEach(completionResponses::add);
56	
57	            forgettingPointRepository.findByPlanId(plan.getId()).stream()
58	                    .map(this::toFpResponse)
59	                    .forEach(fpResponses::add);
60	        }
61	
62	        return StudyExportData.builder()
63	                .userId(userId)
64	                .plans(planResponses)
65	                .completions(completionResponses)
66	                .forgettingPoints(fpResponses)
67	                .exportedAt(LocalDateTime.now().toString())
68	                .build();
69	    }
70	
71	    @Transactional
72	    public String importData(Long userId, StudyExportData data) {
73	        if (data.getPlans() == null || data.getPlans().isEmpty()) {
74	            throw new BusinessException("No study plans found in import data");
75	        }
76	
77	        int importedPlans = 0;
78	        int importedCompletions = 0;
79	        int importedForgettingPoints = 0;
80	
81	        for (StudyPlanResponse planData : data.getPlans()) {
82	            Long oldPlanId = planData.getId();
83	
84	            StudyPlan plan = StudyPlan.builder()
85	                    .userId(userId)
86	                    .courseId(planData.getCourseId())
87	                    .termId(planData.getTermId())
88	                    .title(planData.getTitle())
89	                    .description(planData.getDescription())
90	                    .status(StudyPlan.PlanStatus.ACTIVE)
91	                    .build();
92	            plan = studyPlanRepository.save(plan);
93	            importedPlans++;
94	
95	            // Import completions for this plan
96	            if (data.getCompletions() != null) {
97	                for (DailyCompletionResponse comp : data.getCompletions()) {
98	                    if (comp.getPlanId() != null && comp.getPlanId().equals(oldPlanId)) {
99	                        DailyCompletion completion = DailyCompletion.builder()
100	                                .planId(plan.getId())
101	                                .itemId(comp.getItemId())
102	                                .completedDate(comp.getCompletedDate())
103	                                .completed(comp.isCompleted())
104	                                .notes(comp.getNotes())
105	                                .build();
106	                        completionRepository.save(completion);
107	                        importedCompletions++;
108	                    }
109	                }
110	            }
111	
112	            // Import forgetting points for this plan
113	            if (data.getForgettingPoints() != null) {
114	                for (ForgettingPointResponse fp : data.getForgettingPoints()) {
115	                    if (fp.getPlanId() != null && fp.getPlanId().equals(oldPlanId)) {
116	                        ForgettingPoint point = ForgettingPoint.builder()
117	                                .planId(plan.getId())
118	                                .topic(fp.getTopic())
119	                                .description(fp.getDescription())
120	                                .nextReviewDate(fp.getNextReviewDate())
121	                                .easeFactor(fp.getEaseFactor())
122	                                .intervalDays(fp.getIntervalDays())
123	                                .repetitions(fp.getRepetitions())
124	                                .build();
125	                        forgettingPointRepository.save(point);
126	                        importedForgettingPoints++;
127	                    }
128	                }
129	            }
130	        }
131	
132	        return String.format("Successfully imported %d plans, %d completions, %d forgetting points",
133	                importedPlans, importedCompletions, importedForgettingPoints);
134	    }
