3	import com.campusfit.inbound.entity.*;
4	import com.campusfit.inbound.repository.*;
5	import com.campusfit.shared.exception.BusinessException;
6	import com.campusfit.shared.exception.ResourceNotFoundException;
7	import org.springframework.stereotype.Service;
8	import org.springframework.transaction.annotation.Transactional;
9	
10	import java.math.BigDecimal;
11	import java.util.List;
12	
13	@Service
14	public class InboundStateMachine {
15	
16	    private final InboundReceiptRepository receiptRepository;
17	    private final InboundLineRepository lineRepository;
18	    private final InboundStateHistoryRepository stateHistoryRepository;
19	    private final DiscrepancyRepository discrepancyRepository;
20	    private final PutawayTaskRepository putawayTaskRepository;
21	
22	    public InboundStateMachine(InboundReceiptRepository receiptRepository,
23	                               InboundLineRepository lineRepository,
24	                               InboundStateHistoryRepository stateHistoryRepository,
25	                               DiscrepancyRepository discrepancyRepository,
26	                               PutawayTaskRepository putawayTaskRepository) {
27	        this.receiptRepository = receiptRepository;
28	        this.lineRepository = lineRepository;
29	        this.stateHistoryRepository = stateHistoryRepository;
30	        this.discrepancyRepository = discrepancyRepository;
31	        this.putawayTaskRepository = putawayTaskRepository;
32	    }
33	
34	    @Transactional
35	    public InboundReceipt transition(Long receiptId, InboundReceipt.ReceiptStatus targetState,
36	                                     Long userId, String reason) {
37	        InboundReceipt receipt = receiptRepository.findById(receiptId)
38	                .orElseThrow(() -> new ResourceNotFoundException("InboundReceipt", receiptId));
39	
40	        InboundReceipt.ReceiptStatus currentState = receipt.getStatus();
41	
42	        // Validate transition
43	        validateTransition(receipt, currentState, targetState);
44	
45	        // Record state history
46	        InboundStateHistory history = InboundStateHistory.builder()
47	                .receiptId(receiptId)
48	                .fromState(currentState.name())
49	                .toState(targetState.name())
50	                .changedBy(userId)
51	                .reason(reason)
52	                .build();
53	        stateHistoryRepository.save(history);
54	
55	        // Apply transition
56	        receipt.setStatus(targetState);
57	        return receiptRepository.save(receipt);
58	    }
59	
60	    private void validateTransition(InboundReceipt receipt, InboundReceipt.ReceiptStatus from,
61	                                    InboundReceipt.ReceiptStatus to) {
62	        // Any state can transition to REJECTED
63	        if (to == InboundReceipt.ReceiptStatus.REJECTED) {
64	            return;
65	        }
66	
67	        List<InboundLine> lines = lineRepository.findByReceiptId(receipt.getId());
68	
69	        switch (from) {
70	            case DRAFT:
71	                if (to != InboundReceipt.ReceiptStatus.RECEIVING) {
72	                    throw new BusinessException("DRAFT can only transition to RECEIVING");
73	                }
74	                if (lines.isEmpty()) {
75	                    throw new BusinessException("Receipt must have at least one line to begin receiving");
76	                }
77	                break;
78	
79	            case RECEIVING:
80	                if (to != InboundReceipt.ReceiptStatus.INSPECTION) {
81	                    throw new BusinessException("RECEIVING can only transition to INSPECTION");
82	                }
83	                boolean allReceived = lines.stream()
84	                        .allMatch(l -> l.getReceivedQty().compareTo(BigDecimal.ZERO) > 0);
85	                if (!allReceived) {
86	                    throw new BusinessException("All lines must have received quantity before inspection");
87	                }
88	                break;
89	
90	            case INSPECTION:
91	                if (to != InboundReceipt.ReceiptStatus.PUTAWAY) {
92	                    throw new BusinessException("INSPECTION can only transition to PUTAWAY");
93	                }
94	                boolean allInspected = lines.stream()
95	                        .allMatch(l -> l.getInspectionResult() != InboundLine.InspectionResult.PENDING);
96	                if (!allInspected) {
97	                    throw new BusinessException("All lines must be inspected before putaway");
98	                }
99	                // Check for unresolved discrepancies requiring supervisor
100	                List<Discrepancy> unresolvedSupervisor = discrepancyRepository
101	                        .findByReceiptIdAndSupervisorRequiredTrueAndResolvedByIsNull(receipt.getId());
102	                if (!unresolvedSupervisor.isEmpty()) {
103	                    throw new BusinessException("There are " + unresolvedSupervisor.size() +
104	                            " unresolved discrepancies requiring supervisor approval");
105	                }
106	                break;
107	
108	            case PUTAWAY:
109	                if (to != InboundReceipt.ReceiptStatus.COMPLETED) {
110	                    throw new BusinessException("PUTAWAY can only transition to COMPLETED");
111	                }
112	                List<PutawayTask> pendingTasks = putawayTaskRepository
113	                        .findByReceiptIdAndStatus(receipt.getId(), PutawayTask.TaskStatus.PENDING);
114	                if (!pendingTasks.isEmpty()) {
115	                    throw new BusinessException("All putaway tasks must be completed before marking receipt as COMPLETED");
116	                }
117	                break;
118	
119	            default:
120	                throw new BusinessException("Cannot transition from " + from + " to " + to);
121	        }
122	    }
123	}
