8	import java.util.LinkedHashMap;
9	import java.util.List;
10	import java.util.Map;
11	
12	@Service
13	public class SlowQueryLogService {
14	
15	    private static final Logger log = LoggerFactory.getLogger(SlowQueryLogService.class);
16	
17	    private final JdbcTemplate jdbcTemplate;
18	
19	    public SlowQueryLogService(JdbcTemplate jdbcTemplate) {
20	        this.jdbcTemplate = jdbcTemplate;
21	    }
22	
23	    /**
24	     * Returns slow query performance data from MySQL performance_schema.
25	     * Falls back to table-level metrics if performance_schema queries fail (e.g., H2 in tests).
26	     */
27	    public List<Map<String, Object>> getPerformanceMetrics() {
28	        try {
29	            return jdbcTemplate.query(
30	                    """
31	                    SELECT DIGEST_TEXT AS queryDigest,
32	                           COUNT_STAR AS callCount,
33	                           ROUND(AVG_TIMER_WAIT / 1000000, 0) AS avgDurationMs,
34	                           ROUND(MAX_TIMER_WAIT / 1000000, 0) AS maxDurationMs,
35	                           SUM_ROWS_EXAMINED AS totalRowsExamined,
36	                           FIRST_SEEN AS firstSeen,
37	                           LAST_SEEN AS lastSeen
38	                    FROM performance_schema.events_statements_summary_by_digest
39	                    WHERE SCHEMA_NAME = DATABASE()
40	                      AND DIGEST_TEXT IS NOT NULL
41	                    ORDER BY AVG_TIMER_WAIT DESC
42	                    LIMIT 25
43	                    """,
44	                    (rs, rowNum) -> {
45	                        Map<String, Object> row = new LinkedHashMap<>();
46	                        row.put("query", rs.getString("queryDigest"));
47	                        row.put("callCount", rs.getLong("callCount"));
48	                        row.put("avgDurationMs", rs.getLong("avgDurationMs"));
49	                        row.put("maxDurationMs", rs.getLong("maxDurationMs"));
50	                        row.put("totalRowsExamined", rs.getLong("totalRowsExamined"));
51	                        row.put("firstSeen", rs.getString("firstSeen"));
52	                        row.put("lastSeen", rs.getString("lastSeen"));
53	                        return row;
54	                    });
55	        } catch (Exception e) {
56	            log.warn("performance_schema query failed (possibly running on H2): {}", e.getMessage());
57	            return getTableMetrics();
58	        }
59	    }
60	
61	    private List<Map<String, Object>> getTableMetrics() {
62	        try {
63	            return jdbcTemplate.query(
64	                    """
65	                    SELECT TABLE_NAME AS tableName,
66	                           TABLE_ROWS AS estimatedRows,
67	                           ROUND(DATA_LENGTH / 1024, 0) AS dataSizeKb,
68	                           ROUND(INDEX_LENGTH / 1024, 0) AS indexSizeKb
69	                    FROM information_schema.TABLES
70	                    WHERE TABLE_SCHEMA = DATABASE()
71	                      AND TABLE_TYPE = 'BASE TABLE'
72	                    ORDER BY TABLE_ROWS DESC
73	                    """,
74	                    (rs, rowNum) -> {
75	                        Map<String, Object> row = new LinkedHashMap<>();
76	                        row.put("tableName", rs.getString("tableName"));
77	                        row.put("estimatedRows", rs.getLong("estimatedRows"));
78	                        row.put("dataSizeKb", rs.getLong("dataSizeKb"));
79	                        row.put("indexSizeKb", rs.getLong("indexSizeKb"));
80	                        row.put("status", "OK");
81	                        return row;
82	                    });
83	        } catch (Exception e) {
84	            log.warn("Table metrics query failed: {}", e.getMessage());
85	            return List.of();
86	        }
87	    }
88	}
