32	    @Transactional
33	    public InboundLineResponse addLine(Long receiptId, InboundLineRequest request) {
34	        InboundReceipt receipt = receiptRepository.findById(receiptId)
35	                .orElseThrow(() -> new ResourceNotFoundException("InboundReceipt", receiptId));
36	
37	        if (receipt.getStatus() != InboundReceipt.ReceiptStatus.DRAFT) {
38	            throw new BusinessException("Can only add lines to receipts in DRAFT status");
39	        }
40	
41	        InboundLine line = InboundLine.builder()
42	                .receiptId(receiptId)
43	                .itemCode(request.getItemCode())
44	                .itemName(request.getItemName())
45	                .expectedQty(request.getExpectedQty())
46	                .unitCost(request.getUnitCost() != null ? request.getUnitCost() : BigDecimal.ZERO)
47	                .build();
48	
49	        InboundLine saved = lineRepository.save(line);
50	        return toResponse(saved);
51	    }
52	
53	    @Transactional
54	    public InboundLineResponse updateReceivedQty(Long receiptId, ReceiveLineRequest request) {
55	        InboundLine line = lineRepository.findById(request.getLineId())
56	                .orElseThrow(() -> new ResourceNotFoundException("InboundLine", request.getLineId()));
57	
58	        if (!line.getReceiptId().equals(receiptId)) {
59	            throw new BusinessException("Line does not belong to the specified receipt");
60	        }
61	
62	        line.setReceivedQty(request.getReceivedQty());
63	        InboundLine saved = lineRepository.save(line);
64	
65	        // Auto-detect discrepancy
66	        discrepancyService.detectAndCreate(saved);
67	
68	        return toResponse(saved);
69	    }
