80	
81	        line.setInspectedQty(inspectedQty);
82	        line.setInspectionResult(result);
83	        line.setInspectionNotes(notes);
84	
85	        InboundLine saved = lineRepository.save(line);
86	        return toResponse(saved);
87	    }
