69	    private List<Map<String, Object>> findDuplicateCandidates(List<MasterDataResponse> items, String entityType) {
70	        List<Map<String, Object>> candidates = new ArrayList<>();
71	        for (int i = 0; i < items.size(); i++) {
72	            for (int j = i + 1; j < items.size(); j++) {
73	                MasterDataResponse a = items.get(i);
74	                MasterDataResponse b = items.get(j);
75	                double similarity = calculateSimilarity(a.getName(), b.getName());
76	                if (similarity >= 0.7) {
77	                    Map<String, Object> candidate = new LinkedHashMap<>();
78	                    candidate.put("sourceItem", a);
79	                    candidate.put("targetItem", b);
80	                    candidate.put("similarity", Math.round(similarity * 100) / 100.0);
81	                    candidate.put("entityType", entityType.toUpperCase());
82	                    candidates.add(candidate);
83	                }
84	            }
85	        }
86	        return candidates;
87	    }
88	
89	    private double calculateSimilarity(String a, String b) {
90	        if (a == null || b == null) return 0;
91	        String la = a.toLowerCase().trim();
92	        String lb = b.toLowerCase().trim();
93	        if (la.equals(lb)) return 1.0;
94	        int maxLen = Math.max(la.length(), lb.length());
95	        if (maxLen == 0) return 1.0;
96	        int distance = levenshteinDistance(la, lb);
97	        return 1.0 - ((double) distance / maxLen);
98	    }
99	
100	    private int levenshteinDistance(String a, String b) {
101	        int[][] dp = new int[a.length() + 1][b.length() + 1];
102	        for (int i = 0; i <= a.length(); i++) dp[i][0] = i;
103	        for (int j = 0; j <= b.length(); j++) dp[0][j] = j;
104	        for (int i = 1; i <= a.length(); i++) {
105	            for (int j = 1; j <= b.length(); j++) {
106	                int cost = a.charAt(i - 1) == b.charAt(j - 1) ? 0 : 1;
107	                dp[i][j] = Math.min(Math.min(dp[i - 1][j] + 1, dp[i][j - 1] + 1), dp[i - 1][j - 1] + cost);
108	            }
109	        }
110	        return dp[a.length()][b.length()];
111	    }
112	}
