28	@Component
29	public class SessionAuthenticationFilter extends OncePerRequestFilter {
30	
31	    private static final String AUTHORIZATION_HEADER = "Authorization";
32	    private static final String BEARER_PREFIX = "Bearer ";
33	
34	    private final SessionRepository sessionRepository;
35	    private final UserRepository userRepository;
36	    private final UserRoleRepository userRoleRepository;
37	    private final RoleRepository roleRepository;
38	    private final int sessionTimeoutMinutes;
39	
40	    public SessionAuthenticationFilter(SessionRepository sessionRepository,
41	                                       UserRepository userRepository,
42	                                       UserRoleRepository userRoleRepository,
43	                                       RoleRepository roleRepository,
44	                                       @Value("${app.session.timeout-minutes:30}") int sessionTimeoutMinutes) {
45	        this.sessionRepository = sessionRepository;
46	        this.userRepository = userRepository;
47	        this.userRoleRepository = userRoleRepository;
48	        this.roleRepository = roleRepository;
49	        this.sessionTimeoutMinutes = sessionTimeoutMinutes;
50	    }
