52	    @Override
53	    protected void doFilterInternal(HttpServletRequest request,
54	                                    HttpServletResponse response,
55	                                    FilterChain filterChain) throws ServletException, IOException {
56	        String token = extractToken(request);
57	
58	        if (StringUtils.hasText(token)) {
59	            Optional<Session> sessionOpt = sessionRepository.findByToken(token);
60	
61	            if (sessionOpt.isPresent()) {
62	                Session session = sessionOpt.get();
63	
64	                // Check inactivity-based timeout using lastAccessedAt
65	                LocalDateTime lastActivity = session.getLastAccessedAt() != null
66	                        ? session.getLastAccessedAt()
67	                        : session.getCreatedAt();
68	
69	                boolean isActive = lastActivity != null
70	                        && lastActivity.plusMinutes(sessionTimeoutMinutes).isAfter(LocalDateTime.now());
71	
72	                if (isActive) {
73	                    userRepository.findById(session.getUserId()).ifPresent(user -> {
74	                        List<UserRole> userRoles = userRoleRepository.findByUserId(user.getId());
75	                        Set<String> roles = userRoles.stream()
76	                            .map(ur -> roleRepository.findById(ur.getRoleId())
77	                                .map(r -> r.getCode())
78	                                .orElse(null))
79	                            .filter(r -> r != null)
80	                            .collect(Collectors.toSet());
81	
82	                        UserPrincipal principal = new UserPrincipal(user.getId(), user.getUsername(), roles);
83	
84	                        UsernamePasswordAuthenticationToken authentication =
85	                            new UsernamePasswordAuthenticationToken(principal, null, principal.getAuthorities());
86	                        authentication.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
87	
88	                        SecurityContextHolder.getContext().setAuthentication(authentication);
89	
90	                        // Refresh last accessed time (sliding window)
91	                        session.setLastAccessedAt(LocalDateTime.now());
92	                        session.setExpiresAt(LocalDateTime.now().plusMinutes(sessionTimeoutMinutes));
93	                        sessionRepository.save(session);
94	                    });
95	                }
96	            }
97	        }
98	
99	        filterChain.doFilter(request, response);
100	    }
101	
102	    private String extractToken(HttpServletRequest request) {
103	        String bearerToken = request.getHeader(AUTHORIZATION_HEADER);
104	        if (StringUtils.hasText(bearerToken) && bearerToken.startsWith(BEARER_PREFIX)) {
105	            return bearerToken.substring(BEARER_PREFIX.length());
106	        }
107	        return null;
108	    }
